document.addEventListener("DOMContentLoaded",()=>{"use strict";const e=document.querySelectorAll(".edge-card"),t=document.querySelector(".trusted-section"),s=new IntersectionObserver((e,t)=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.contains("edge-card")?(e.target.classList.add("visible"),t.unobserve(e.target)):e.target.classList.contains("trusted-section")&&(e.target.classList.add("scrolled"),t.unobserve(e.target)))})},{root:null,rootMargin:"0px",threshold:.2});e.forEach(e=>s.observe(e)),t&&s.observe(t)});
